import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as o,N as i,E as n,P as a,W as s}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const k={id:"delegation",title:"Delegation and Sub-Agents",description:"The art of knowing when one agent is not enough — spawning specialists, designing tasks, and avoiding common pitfalls.",icon:"🔀",colorHex:"#7c3aed",difficulty:"advanced",estimatedHours:12,prerequisites:["agent-runtime","state-and-memory"],chapters:[{id:"c1-when-to-delegate",title:"When to Delegate",description:"The decision framework for single-agent vs multi-agent approaches.",difficulty:"intermediate",estimatedMinutes:80,sections:[{id:"s1-single-agent-ceiling",title:"The Single-Agent Ceiling",description:"Tasks too large or complex for one agent — recognizing the limits.",difficulty:"intermediate",readingMinutes:10},{id:"s2-delegation-decision",title:"The Delegation Decision",description:"Do it yourself vs spawn a helper — a practical decision framework.",difficulty:"intermediate",readingMinutes:12},{id:"s3-types-specialists",title:"Types of Specialists",description:"Explorers, planners, verifiers, and guides — roles agents can fill.",difficulty:"intermediate",readingMinutes:10},{id:"s4-foreground-background",title:"Foreground vs Background",description:"Blocking and non-blocking delegation — when to wait and when to proceed.",difficulty:"intermediate",readingMinutes:10}]},{id:"c2-designing-tasks",title:"Designing Delegated Tasks",description:"How to write effective sub-agent briefs and collect results.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-sub-agent-brief",title:"Writing a Sub-Agent Brief",description:"Clear, complete, self-contained — the art of the perfect handoff.",difficulty:"advanced",readingMinutes:12},{id:"s2-scoping-capabilities",title:"Scoping Capabilities",description:"Giving a sub-agent only what it needs — the principle of minimal toolset.",difficulty:"advanced",readingMinutes:10},{id:"s3-isolation",title:"Isolation",description:"Giving each agent its own workspace — preventing interference between workers.",difficulty:"advanced",readingMinutes:12},{id:"s4-collecting-results",title:"Collecting and Integrating Results",description:"What comes back from a sub-agent and how to merge it into the main workflow.",difficulty:"advanced",readingMinutes:10}]},{id:"c3-anti-patterns",title:"Delegation Anti-Patterns",description:"Common mistakes when delegating to sub-agents and how to avoid them.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-over-delegation",title:"Over-Delegation",description:"Spawning agents for trivial tasks — the overhead that kills performance.",difficulty:"intermediate",readingMinutes:10},{id:"s2-duplicate-work",title:"Duplicate Work",description:"Parent and child solving the same problem — wasted tokens and time.",difficulty:"intermediate",readingMinutes:10},{id:"s3-context-overload",title:"Context Overload",description:"Giving too much information — when more context makes agents worse.",difficulty:"advanced",readingMinutes:10},{id:"s4-orphan-agents",title:"Orphan Agents",description:"Failing to track or clean up spawned helpers — resource leaks in multi-agent systems.",difficulty:"advanced",readingMinutes:12}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Single-Agent Ceiling"}),e.jsx("p",{children:"A single agent running in a loop is a powerful thing. It can plan, use tools, recover from errors, and carry out multi-step tasks — all within one continuous thread of reasoning. But that single thread has natural limits. As tasks grow longer, broader, or more parallel in nature, a lone agent begins to strain. Understanding where that strain starts is the first step toward knowing when to delegate."}),e.jsx(t,{title:"The Single-Agent Ceiling",number:"Concept 7.1",children:"The single-agent ceiling is the point at which one agent's context window, sequential execution, or skill set becomes the bottleneck. Past this ceiling, adding more instructions to the same agent yields diminishing returns — or outright failure. The ceiling is not a flaw; it is an architectural signal that the problem requires more than one worker."}),e.jsxs("p",{children:["Three forces drive an agent toward its ceiling. First, ",e.jsx("strong",{children:"context length"}),": every observation, tool call, and intermediate result consumes tokens. Long-running tasks can exhaust the window, forcing the agent to lose earlier context. Second,",e.jsx("strong",{children:" serial execution"}),": an agent works step-by-step. Tasks with independent sub-problems waste time when forced through a single pipeline. Third,",e.jsx("strong",{children:" domain breadth"}),": an agent prompted to be a generalist at everything is usually excellent at nothing in particular."]}),e.jsx(o,{title:"The One-Person Consultancy",children:"A freelance consultant can handle a small engagement solo — a few interviews, a report, a presentation. But a project that requires simultaneous legal review, financial modelling, and technical audit cannot be done by one person without serious delays and quality trade-offs. The engagement has outgrown a solo worker. The answer is not to work the consultant harder; it is to assemble a team."}),e.jsx(i,{type:"tip",title:"Signals You Have Hit the Ceiling",children:"Watch for these signs: the agent repeatedly re-reads earlier context as if it forgot it; tasks that could proceed in parallel are stuck waiting on each other; the agent produces shallow results on topics that deserve deep expertise; or the task simply exceeds the maximum context length of the model."}),e.jsx(n,{title:"Recognising the Single-Agent Ceiling",exercises:[{id:"sac-1",difficulty:"beginner",question:"List three observable symptoms that suggest a single agent has reached its ceiling on a task. For each symptom, explain the underlying architectural cause.",hint:"Think about context length, sequential bottlenecks, and knowledge breadth separately.",solution:"(1) Repeating earlier mistakes or ignoring prior context — caused by context window exhaustion. (2) Tasks completing far slower than expected despite simple sub-steps — caused by forced serial execution of parallelisable work. (3) Shallow or generic answers on specialised topics — caused by a single generalist prompt unable to match domain-specific depth."},{id:"sac-2",difficulty:"intermediate",question:"A task requires researching five independent topics and then synthesising them into a report. Why does a single-agent approach struggle here, and what exactly would a delegated approach fix?",hint:"Consider both the parallelism opportunity and the context budget separately.",solution:"A single agent must research all five topics sequentially, each consuming context. By the time it reaches synthesis, earlier research may have been displaced or compressed. A delegated approach assigns each research topic to a separate sub-agent, running in parallel. Each sub-agent has a clean context for its domain. The orchestrating agent then receives only the final summaries — a small, high-signal input rather than the full accumulated history."},{id:"sac-3",difficulty:"advanced",question:"Under what conditions would splitting a task across multiple agents actually make performance worse rather than better? Identify at least two such conditions.",hint:"Think about coordination overhead and tasks where sub-results depend tightly on each other.",solution:"(1) High-interdependence tasks: if every sub-result depends on the previous one, parallelism offers no benefit but adds hand-off latency and serialisation overhead. (2) Short tasks: the overhead of spawning, briefing, and collecting results from sub-agents may exceed the time the task itself would take in a single agent. (3) Tasks requiring shared evolving state: if each agent needs to read and write to the same state, synchronisation complexity can introduce errors and deadlocks that would not exist in a single sequential agent."}]})]})}const x=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Delegation Decision"}),e.jsx("p",{children:"Knowing the single-agent ceiling exists is not enough — you need a practical way to decide whether a given task warrants delegation. Delegation has real costs: coordination overhead, more complex error handling, and harder observability. It should be a deliberate choice, not a reflex."}),e.jsx(t,{title:"The Delegation Decision",number:"Concept 7.2",children:"The delegation decision is the evaluation of whether handing a sub-task to another agent produces a better outcome than keeping it in the current agent's loop. It involves three dimensions: parallelism value (can this work happen concurrently?), specialisation value (does this sub-task benefit from a focused prompt and context?), and context economy (does keeping this work in the parent consume context that outweighs the coordination cost?)."}),e.jsx("p",{children:`A useful mental test: imagine running the task twice — once inside the current agent, once in a fresh sub-agent. Which produces better output? Which finishes faster? If the answer is "sub-agent" on at least two of those three dimensions, delegation is likely worth it. If the answer is "it's roughly the same," the overhead of delegation probably isn't justified.`}),e.jsx(a,{title:"Delegate for Independence, Not for Size",number:"Principle 7.1",children:"The best candidates for delegation are sub-tasks that can be fully specified upfront and completed without needing to continuously consult the parent. Task independence — not task size — is the primary criterion. A large but tightly coupled sub-task is often better kept in-process; a small but genuinely independent one may be worth delegating."}),e.jsx(i,{type:"intuition",title:"The Brief Test",children:"Before delegating, ask: can you write a complete, self-contained brief for the sub-agent right now — all the context it needs, a clear goal, and an unambiguous success condition? If you cannot write that brief without referencing live state from the parent's ongoing reasoning, the task is not yet ready to delegate."}),e.jsx(n,{title:"Making the Delegation Decision",exercises:[{id:"dd-1",difficulty:"beginner",question:"For each of the following sub-tasks, decide whether it is a good candidate for delegation and explain why: (a) searching a database for a single record; (b) writing a full legal analysis of a contract; (c) summarising a paragraph.",hint:"Apply the three dimensions: parallelism value, specialisation value, context economy.",solution:"(a) Searching for a single record: poor candidate — fast, low context, no specialisation benefit. (b) Legal analysis: strong candidate — domain-specialised prompt produces better output, and it is a self-contained sub-task. (c) Summarising a paragraph: poor candidate — trivial task, overhead of spawning a sub-agent would dominate."},{id:"dd-2",difficulty:"intermediate",question:"An orchestrating agent is halfway through a complex task and realises it needs to gather information from three different external sources. At that point, can it safely delegate the gathering? What must be true for delegation to work well here?",hint:"Think about the brief test — what does each sub-agent need to know?",solution:"Yes, if the orchestrator can write a complete brief for each gathering sub-agent using only information already resolved. Each sub-agent needs a specific query and an endpoint — no dependency on each other or on the parent's future reasoning. The gathering tasks are parallel and independent, making this a clean delegation scenario."},{id:"dd-3",difficulty:"advanced",question:"Design a simple scoring rubric (three criteria, each scored 0–2) that an orchestrating agent could use to decide whether to delegate a sub-task. Explain what each criterion measures and what score threshold triggers delegation.",hint:"Base criteria on parallelism, independence, and specialisation.",solution:"Criteria: (1) Parallelism score (0–2): 0 if the sub-task must complete before the next step; 2 if it can run concurrently with other work. (2) Independence score (0–2): 0 if the sub-task needs continuous access to parent state; 2 if it can be fully specified upfront. (3) Specialisation score (0–2): 0 if any general prompt handles it well; 2 if a focused specialist prompt produces materially better results. Threshold: delegate if total >= 4. Score 3 is marginal — consider task duration before deciding."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Types of Specialist Sub-Agents"}),e.jsx("p",{children:"Not all sub-agents are alike. When an orchestrator delegates, it can choose from several archetypes — each shaped by the kind of work it excels at. Understanding these archetypes helps an orchestrator match the right sub-agent type to the right task rather than spawning generic workers for every job."}),e.jsxs(t,{title:"Specialist Sub-Agent Archetypes",number:"Concept 7.3",children:["A specialist sub-agent is a sub-agent configured with a narrow, focused prompt and tool set aimed at one category of work. Common archetypes include: the ",e.jsx("strong",{children:"researcher"}),"(retrieves and summarises information from sources), the ",e.jsx("strong",{children:"executor"})," (carries out deterministic actions like writing files or calling APIs), the ",e.jsx("strong",{children:"critic"}),"(evaluates output quality and flags issues), and the ",e.jsx("strong",{children:"planner"})," (breaks a vague objective into concrete steps). Each archetype has a characteristic input, output, and failure mode."]}),e.jsx("p",{children:"Archetypes are not rigid categories — they are design patterns. A single sub-agent might blend researcher and critic behaviour. The value of naming these patterns is not to enforce strict separation but to prompt intentional design. When you know what role a sub-agent is playing, you can write a sharper prompt, choose the right tools, and anticipate how it can fail."}),e.jsx(o,{title:"The Hospital Specialist Referral",children:"A general practitioner diagnoses broadly, then refers patients to cardiologists, radiologists, or surgeons for specific work. Each specialist has deep expertise in a narrow domain, the right equipment, and a clear protocol for what they return to the GP. The GP does not try to perform the MRI scan or the bypass surgery — they delegate to the right specialist and integrate the results into an overall care plan."}),e.jsx(i,{type:"note",title:"The Critic Archetype",children:"The critic sub-agent is underused but highly valuable. Rather than having an orchestrator self-evaluate its own work — which suffers from the same blind spots as the original reasoning — a separate critic agent reviews output with a clean perspective. Because the critic starts with no prior commitment to the output, it catches errors the producer missed."}),e.jsx(n,{title:"Matching Archetypes to Tasks",exercises:[{id:"ts-1",difficulty:"beginner",question:"For each archetype — researcher, executor, critic, planner — give one concrete task that fits well and one task that fits poorly. Explain your reasoning.",hint:"Think about what input each archetype needs and what it returns.",solution:'Researcher: good fit = "find all published papers on X from 2023"; poor fit = "deploy the application" (execution, not retrieval). Executor: good fit = "write these five files to disk"; poor fit = "evaluate the quality of this essay" (judgement, not action). Critic: good fit = "review this draft for logical consistency"; poor fit = "search the web for recent news" (retrieval, not evaluation). Planner: good fit = "outline the steps to migrate a database"; poor fit = "execute step 3 of the migration plan" (execution, not planning).'},{id:"ts-2",difficulty:"intermediate",question:"An orchestrator is producing a research report. Design a pipeline using at least three specialist archetypes. Specify what each sub-agent receives as input, what it returns, and how the orchestrator uses its output.",hint:"Think about what needs to happen before synthesis can occur.",solution:"Pipeline: (1) Planner receives the report topic and returns a structured outline with section titles and research questions. (2) Researcher(s) — one per section — receive a single research question and return a summary with source citations. (3) Critic receives the assembled draft and returns a list of gaps, inconsistencies, or unsupported claims. Orchestrator incorporates the critic's feedback before finalising the report."},{id:"ts-3",difficulty:"advanced",question:"What are the failure modes specific to the critic archetype? How would you design the critic's prompt and task brief to minimise each failure mode?",hint:"Consider what can go wrong when the critic has too little context, too much context, or the wrong evaluation criteria.",solution:"Failure modes: (1) Under-specification — critic lacks criteria, produces vague feedback. Fix: include explicit rubric in the brief. (2) Leniency bias — critic is too agreeable. Fix: instruct the critic to find at least N issues and to assume the work may contain errors. (3) Context starvation — critic doesn't know the original goal, so it evaluates against the wrong standard. Fix: always include the original task specification in the critic's brief alongside the output to review. (4) Over-correction — critic flags style preferences as errors. Fix: distinguish required corrections from optional suggestions in the rubric."}]})]})}const T=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Foreground and Background Delegation"}),e.jsx("p",{children:"When an orchestrator delegates a task, it must decide whether to wait for the result before continuing or move on and collect the result later. This choice — foreground versus background — affects throughput, complexity, and how the orchestrator manages its own context and state."}),e.jsxs(t,{title:"Foreground vs Background Delegation",number:"Concept 7.4",children:["In ",e.jsx("strong",{children:"foreground delegation"}),", the orchestrator invokes a sub-agent and blocks until it receives the result. The sub-agent's output feeds directly into the next step. In ",e.jsx("strong",{children:"background delegation"}),", the orchestrator hands off work and continues its own processing, collecting results asynchronously at a later point. Foreground is simpler and keeps reasoning sequential; background unlocks parallelism but requires the orchestrator to manage pending work and handle late or missing results."]}),e.jsx("p",{children:"Foreground delegation is the right default when the result of the sub-task is immediately required — when the next reasoning step depends on knowing the outcome. Background delegation pays off when multiple independent sub-tasks can run concurrently and the orchestrator has meaningful work to do while waiting. Using background delegation for everything creates complexity without benefit; using foreground delegation for everything sacrifices the parallelism advantage of multi-agent systems."}),e.jsx(a,{title:"Match Delegation Mode to Data Dependency",number:"Principle 7.2",children:"Use foreground delegation when the sub-task result is a prerequisite for the next decision. Use background delegation when the sub-task is independent of the orchestrator's next steps. The dependency structure of the task — not the desire for speed — should drive the choice."}),e.jsx(i,{type:"tip",title:"Collecting Background Results",children:"When using background delegation, design explicit collection points: moments in the orchestrator's plan where it pauses, gathers all outstanding sub-agent results, and integrates them before proceeding. Collecting too early (before results are ready) wastes cycles; collecting too late (after the orchestrator has already made decisions that depended on those results) causes errors."}),e.jsx(n,{title:"Foreground vs Background Trade-offs",exercises:[{id:"fb-1",difficulty:"beginner",question:"Give one scenario where foreground delegation is clearly the right choice and one where background delegation is clearly better. Explain the key difference.",hint:"Focus on whether the orchestrator can make progress before the sub-agent finishes.",solution:"Foreground: the orchestrator asks a sub-agent to retrieve the current stock price before deciding whether to generate a buy or sell recommendation. The decision cannot proceed without the price. Background: the orchestrator delegates five independent data-gathering tasks simultaneously and will synthesise results later; it can do other planning work while they run."},{id:"fb-2",difficulty:"intermediate",question:"An orchestrator uses background delegation for three sub-agents. One sub-agent fails partway through. Describe two different strategies for handling this and the trade-offs of each.",hint:"Think about retry, skip, and fallback strategies.",solution:"(1) Retry with timeout: the orchestrator waits a fixed period and re-delegates the failed task. Simple to implement, but increases latency and requires careful timeout tuning. (2) Graceful degradation: the orchestrator marks the sub-task as failed, proceeds with available results, and notes the gap in its final output. Faster overall, but the output is incomplete — acceptable if partial results have value."},{id:"fb-3",difficulty:"advanced",question:"Design a collection-point strategy for an orchestrator managing ten background sub-agents whose results are needed in three different later stages of the plan. How should the orchestrator group and time its collection points?",hint:"Think about grouping sub-agents by which stage depends on them, not by when they finish.",solution:"Group sub-agents by the stage that consumes their output: sub-agents whose results feed Stage A are collected just before Stage A begins; sub-agents for Stage B are collected before Stage B. This minimises idle waiting (the orchestrator proceeds until it needs a group's results) without requiring all results upfront. The orchestrator maintains a dependency map: stage -> required sub-agent IDs. Before each stage, it checks whether required results are available, blocks if not, and resumes as soon as the group is complete."}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Writing a Sub-Agent Brief"}),e.jsx("p",{children:"The quality of delegation hinges almost entirely on the quality of the brief given to the sub-agent. A vague brief produces vague work. A brief with missing context forces the sub-agent to guess. A brief with conflicting signals produces confused output. Investing care in the brief is the highest-leverage act an orchestrator can perform."}),e.jsxs(t,{title:"The Sub-Agent Brief",number:"Concept 7.5",children:["A sub-agent brief is the complete specification passed to a sub-agent at the moment of delegation. A well-formed brief contains four elements: the ",e.jsx("strong",{children:"goal"}),"(what outcome is expected), the ",e.jsx("strong",{children:"context"})," (the relevant background the sub-agent cannot infer), the ",e.jsx("strong",{children:"constraints"})," (boundaries on how the work should be done), and the ",e.jsx("strong",{children:"output format"})," (how the result should be returned). Missing any element forces the sub-agent to improvise, which often leads to results the orchestrator cannot use."]}),e.jsx(o,{title:"The Project Manager's Assignment Slip",children:`A good project manager doesn't hand a task to a team member with just "figure out the database migration." They write: here is the goal, here is what you already know about the system, here are the constraints (no downtime, finish by Friday), and here is what I need back from you (a migration script and a rollback plan). Each element prevents a different category of failure. The goal prevents misaligned effort. The context prevents wasted research. The constraints prevent boundary violations. The output format prevents unusable deliverables.`}),e.jsx(a,{title:"The Brief Must Be Self-Contained",number:"Principle 7.3",children:"A sub-agent should be able to complete its task using only the brief and its own tools. If the sub-agent would need to ask clarifying questions to proceed, the brief is incomplete. Write the brief as if the sub-agent has no memory of prior conversations and no access to the orchestrator's current reasoning — because it doesn't."}),e.jsx(n,{title:"Crafting Sub-Agent Briefs",exercises:[{id:"sab-1",difficulty:"beginner",question:'Review this brief: "Search the web for information about the topic and summarise what you find." Identify which of the four brief elements (goal, context, constraints, output format) are missing or underspecified.',hint:"Check each element: is the goal clear? Is any context given? Are there constraints? Is the output format defined?",solution:"Goal: partially present but missing specificity (what topic? what kind of information?). Context: entirely absent — no background on why this information is needed or what the orchestrator already knows. Constraints: absent — no time period, source type, length, or quality criteria. Output format: absent — the sub-agent does not know whether to return bullet points, prose, citations, or a structured object."},{id:"sab-2",difficulty:"intermediate",question:'Write an improved version of the brief: "Search the web for information about the topic and summarise what you find." The topic is recent advances in battery technology for electric vehicles. The orchestrator needs three key findings with source URLs, each fitting in one sentence, for inclusion in a technical report.',hint:"Include all four elements and be specific.",solution:'Improved brief: "Goal: Identify three notable advances in lithium-ion or solid-state battery technology for electric vehicles published in the last 18 months. Context: This summary will be included in a technical report for automotive engineers; assume a technical audience. Constraints: Only use sources from recognised technical publications, industry reports, or peer-reviewed outlets. Avoid marketing material. Output format: Return exactly three findings. Each finding: one sentence (max 30 words) describing the advance, plus the URL of the primary source."'},{id:"sab-3",difficulty:"advanced",question:"An orchestrator is delegating a task that depends on a decision it made earlier in its reasoning (e.g., it chose Strategy B over Strategy A). How should it encode that prior decision in the sub-agent brief without passing the entire conversation history?",hint:"Think about extracting only the relevant resolved facts, not the full reasoning chain.",solution:'The orchestrator should extract the decision as a resolved fact: "The approach chosen for this project is Strategy B (incremental rollout, starting with the EU region). Do not consider Strategy A." It passes only the conclusion and the constraints that flow from it — not the deliberation. This keeps the brief concise while giving the sub-agent the context it needs. Passing the full history risks confusing the sub-agent with superseded considerations.'}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Scoping Sub-Agent Capabilities"}),e.jsx("p",{children:"Every sub-agent is equipped with tools and permissions at the moment it is created. Choosing which tools to give a sub-agent is not a minor implementation detail — it determines what the sub-agent can do, what it cannot do, and what damage it can cause if it reasons incorrectly. Capability scoping is a safety and design decision in equal measure."}),e.jsx(t,{title:"Capability Scoping",number:"Concept 7.6",children:"Capability scoping is the deliberate restriction of a sub-agent's tools and permissions to only those required for its assigned task. A sub-agent that only needs to read a database should not have write permissions. One that only needs to search the web should not have access to the file system. Narrowing the capability set reduces the blast radius of mistakes and makes the sub-agent's behaviour easier to predict and audit."}),e.jsxs("p",{children:["Two principles drive capability scoping. The first is the ",e.jsx("em",{children:"principle of least privilege"}),": grant only what is needed for the task at hand. The second is",e.jsx("em",{children:" clarity of purpose"}),": a tightly scoped tool set shapes the sub-agent's behaviour. An agent that can only search and summarise will not be tempted to start writing files. The constraints in the tool set reinforce the constraints in the prompt."]}),e.jsx(a,{title:"Tools as Implicit Permissions",number:"Principle 7.4",children:'Every tool granted to a sub-agent is an implicit permission. Granting a tool says "this agent is allowed to do this." Granting a destructive tool without need is not just wasteful — it is a signal that the scoping was not carefully considered. Tool grants should be as deliberate as permission grants in any other security-conscious system.'}),e.jsx(s,{title:"The Temptation of the Full Toolkit",children:'A common mistake is to give every sub-agent the same comprehensive tool set "just in case." This eliminates the safety benefit of scoping, makes sub-agent behaviour harder to predict, and increases the surface area for errors. Sub-agents with broad capabilities sometimes use tools that were not intended for their task — not because they are misbehaving, but because those tools appeared relevant to their reasoning.'}),e.jsx(n,{title:"Scoping Capabilities Correctly",exercises:[{id:"sc-1",difficulty:"beginner",question:"A sub-agent's task is to summarise five web pages. List the tools it needs and the tools it should explicitly not have. Justify each exclusion.",hint:"Think about what actions the task requires versus what actions could cause unintended side effects.",solution:"Needs: web fetch/browser tool (to retrieve page content), text processing or summarisation capability. Should not have: file write tools (no need to persist output directly), database access (irrelevant to the task), email or notification tools (no communication needed), code execution (summarisation is language-only). Each exclusion prevents a category of unintended action."},{id:"sc-2",difficulty:"intermediate",question:"A sub-agent is assigned to validate a set of configuration files and report any errors. During validation it discovers the files contain what looks like a security vulnerability. With a read-only tool set, what happens? Is that the right outcome?",hint:"Consider the difference between reporting and acting, and whether the sub-agent should fix or flag.",solution:"With a read-only tool set, the sub-agent can only report the vulnerability — it cannot fix it. This is the correct outcome: fixing a security vulnerability is a consequential action that should go through the orchestrator and likely require human review. A sub-agent with write permissions might attempt an automated fix that inadvertently breaks other configurations. Read-only scoping forces the decision back to the appropriate authority level."},{id:"sc-3",difficulty:"advanced",question:"Design a capability tiering model for sub-agents in a content publishing workflow. Define three tiers (read-only, write-draft, publish) and specify which tasks belong in each tier and why.",hint:"Think about the reversibility and blast radius of each tier's actions.",solution:"Tier 1 (read-only): research agents, fact-checkers, content auditors — their mistakes are costless because no state changes. Tier 2 (write-draft): copywriters, editors — they can create and modify draft content but cannot publish. Errors are recoverable; a human or reviewer agent can catch problems before they go live. Tier 3 (publish): the final publishing agent — should be narrow in scope, only able to mark content as published after receiving explicit approval signal. The progression from tier to tier mirrors increasing irreversibility of action."}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Isolating Sub-Agents"}),e.jsx("p",{children:"When multiple sub-agents run in the same system, they share an environment: the same file system paths, the same external APIs, potentially the same databases. Without deliberate isolation, sub-agents can interfere with each other in ways that are hard to debug and harder to predict. Isolation is the design practice that prevents those collisions."}),e.jsxs(t,{title:"Sub-Agent Isolation",number:"Concept 7.7",children:["Isolation is the property that one sub-agent's actions cannot unintentionally affect another sub-agent's work. Isolation operates at multiple levels: ",e.jsx("strong",{children:"context isolation"})," (each sub-agent has its own conversation context without access to others'), ",e.jsx("strong",{children:"data isolation"})," (sub-agents write to separate namespaces, directories, or records), and ",e.jsx("strong",{children:"tool isolation"})," (tools do not share mutable internal state). A system with poor isolation produces race conditions, corrupt shared state, and outputs that depend on execution ordering in unpredictable ways."]}),e.jsx("p",{children:"Context isolation is automatic in most agent frameworks — each sub-agent starts a fresh conversation. Data isolation requires deliberate design. If two sub-agents both write to the same file path or the same database table, the last writer wins — or worse, both writes partially succeed and the result is malformed. The solution is namespacing: giving each sub-agent a unique scope for any shared resource it touches."}),e.jsxs(i,{type:"intuition",title:"The Namespace Pattern",children:["A simple and effective isolation strategy is to assign each sub-agent a unique ID at creation time and use that ID as a prefix or namespace for any resource it creates. Sub-agent A writes to ",e.jsx("code",{children:"task-A/output.json"}),"; sub-agent B writes to",e.jsx("code",{children:"task-B/output.json"}),". The orchestrator knows where to find each result and there is no possibility of collision."]}),e.jsx(s,{title:"Shared Tool State",children:"Some tools maintain internal state — a browser session, an authenticated API client, a database connection pool. If sub-agents share a tool instance, one agent's actions (logging in, navigating, modifying session state) affect the tool's state for all other agents using it. Either give each sub-agent its own tool instance or design tools to be stateless and re-entrant."}),e.jsx(n,{title:"Designing for Isolation",exercises:[{id:"iso-1",difficulty:"beginner",question:'Three sub-agents are all writing their outputs to a single shared "results" file. Describe two ways this can go wrong, even if each agent produces correct output individually.',hint:"Think about concurrent writes and overwriting.",solution:"(1) Race condition: two agents finish at nearly the same time and both write to the file simultaneously. Depending on the file system, this produces a corrupt or interleaved file. (2) Overwriting: the last agent to write replaces the earlier agents' results entirely, so only one result is preserved. Even with sequential writes, the output format may not support appending multiple results correctly."},{id:"iso-2",difficulty:"intermediate",question:"An orchestrator spawns five researcher sub-agents to query the same external API. The API has a rate limit of 10 requests per minute. How does poor isolation lead to rate limit errors, and how would you design around this?",hint:"Think about what each agent sees when it decides how many requests to make.",solution:`Each agent independently decides how many requests to make based on its own task, with no visibility into the other agents' request counts. Together they exceed the rate limit, causing failures. Design solutions: (1) Route all API calls through a shared, rate-aware proxy tool that queues requests across agents. (2) Pre-allocate request quotas per agent in the brief ("you may make at most 2 API calls"). (3) Stagger agent launch times so they don't all burst simultaneously.`},{id:"iso-3",difficulty:"advanced",question:"Design an isolation contract for a multi-agent data-processing pipeline where sub-agents read from a shared input dataset and write results to a shared output store. What rules must each sub-agent follow, and how does the orchestrator enforce them?",hint:"Think about read vs write isolation separately, and about what the orchestrator tracks.",solution:"Read isolation: sub-agents may read any record from the input dataset but must not modify it. Enforced by granting read-only access to the input store. Write isolation: each sub-agent writes only to its own namespace (e.g., keyed by agent ID) in the output store. Enforced by scoping the write tool to a specific path prefix at creation time. The orchestrator tracks a registry of agent IDs to output paths and uses this to collect and merge results after all agents complete. Collision-free merging is guaranteed because paths never overlap."}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Collecting and Integrating Sub-Agent Results"}),e.jsx("p",{children:"Delegation is not complete when the sub-agent finishes — it is complete when the orchestrator has successfully integrated the result into its own reasoning. The collection and integration step is where many multi-agent systems silently fail: sub-agents finish correctly but their results are misread, incompatibly formatted, or ignored when they arrive after the orchestrator has already moved on."}),e.jsxs(t,{title:"Result Collection",number:"Concept 7.8",children:["Result collection is the process by which an orchestrating agent retrieves sub-agent outputs and incorporates them into its own state or plan. Collection requires three things: ",e.jsx("strong",{children:"a contract"})," (both parties agreed on the output format upfront),",e.jsx("strong",{children:"a retrieval mechanism"})," (the orchestrator knows how and where to find each result), and ",e.jsx("strong",{children:"a validation step"})," (the orchestrator checks that the result matches the contract before acting on it). Skipping validation is the most common collection mistake."]}),e.jsx("p",{children:"Output format contracts deserve explicit attention. If an orchestrator expects a JSON object with a specific schema and receives a prose paragraph, it cannot use the result without an additional parsing step — which may itself introduce errors. Specifying the output format in the brief is an investment that pays off at collection time: it shifts the formatting responsibility to the sub-agent, where it is cheaper to enforce."}),e.jsx(a,{title:"Validate Before You Integrate",number:"Principle 7.5",children:"Before incorporating a sub-agent's result into downstream reasoning, verify that it meets the expected schema and contains the required fields. A malformed or partial result silently propagated into a plan is more dangerous than a clearly flagged failure. The orchestrator should treat missing or malformed results as explicit failures, not as implicit successes."}),e.jsx(i,{type:"tip",title:"Handling Partial Results",children:"Not every sub-task needs to fully succeed for the overall task to be usable. Design collection logic to distinguish between results that are required (the plan cannot proceed without them) and results that are enriching (the plan is better with them but can proceed without). Treating all results as required creates unnecessary blockage; treating all as optional risks producing an output based on incomplete data."}),e.jsx(n,{title:"Designing Robust Result Collection",exercises:[{id:"cr-1",difficulty:"beginner",question:'An orchestrator receives this result from a sub-agent asked to find a product price: "The price is approximately twenty dollars, though it varies by region." Why is this a problematic result, and what output format contract would have prevented it?',hint:"Think about what the orchestrator needs to use this value programmatically.",solution:'The result is ambiguous ("approximately"), imprecise ("twenty dollars" is prose, not a number), and incomplete (no specific region, no currency symbol). A contract would specify: return a JSON object with fields { "price_usd": number, "region": string, "source_url": string, "retrieved_at": ISO-8601 timestamp }. The sub-agent must return structured data the orchestrator can use without additional parsing or interpretation.'},{id:"cr-2",difficulty:"intermediate",question:"Five sub-agents run in parallel. Two return results quickly; two return results after a long delay; one never returns. How should the orchestrator handle this situation at each of its collection points?",hint:"Think about timeouts, partial collection, and distinguishing required from optional results.",solution:"At the collection point: (1) Check which results are available. Use the two fast results immediately if they are not interdependent with the slow ones. (2) Set a timeout for the two slow agents. If they arrive within the window, integrate them; if not, mark them as timed-out and note the gap. (3) After a second timeout for the non-returning agent, mark it as failed. If its result is required, halt and report failure; if optional, proceed and annotate the output with the missing data. Log all outcomes for observability."},{id:"cr-3",difficulty:"advanced",question:"Two sub-agents independently research the same question and return contradictory answers. How should the orchestrator handle this contradiction? Design a resolution strategy that does not simply discard one result.",hint:"Think about using a critic agent, surfacing the contradiction explicitly, or triangulating with a third source.",solution:"Strategy: (1) Surface the contradiction explicitly in the orchestrator's state rather than silently picking one answer. (2) Spawn a critic or arbitration sub-agent with both results and the original question, tasked with evaluating which result is better supported or whether both can be true in different contexts. (3) If the critic cannot resolve it, include both results in the final output with appropriate uncertainty framing rather than presenting a false consensus. Contradictions that cannot be resolved should be visible to downstream consumers, not hidden."}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Over-Delegation"}),e.jsx("p",{children:"Delegation is a tool, and like any tool it can be overused. An orchestrator that reflexively delegates every sub-task — regardless of size, complexity, or independence — creates a system that is harder to reason about, slower, and more prone to failure than a single agent handling the same work directly. This pattern is called over-delegation."}),e.jsx(t,{title:"Over-Delegation",number:"Concept 7.9",children:"Over-delegation occurs when an orchestrator delegates sub-tasks that would be more efficiently handled within its own reasoning loop. The signs are: an orchestrator that spawns sub-agents for trivial one-step tasks; delegation chains where every level immediately delegates to the next without doing any work; and orchestrators whose coordination overhead exceeds the value produced by any individual sub-agent."}),e.jsx("p",{children:"The appeal of over-delegation is understandable. Delegation feels like architecture. Breaking work into pieces feels like good design. But the purpose of delegation is to overcome a real limitation — parallelism, specialisation, context economy — not to add structure for its own sake. When the limitation doesn't exist, delegation adds latency, complexity, and failure modes without compensating benefit."}),e.jsx(o,{title:"The Manager Who Delegates Everything",children:"A manager who delegates every task — including reading their own emails and writing single-sentence replies — is not being strategic. They spend more time writing delegation briefs and reviewing results than the tasks originally required. Their direct reports are overwhelmed with trivial assignments while the manager adds no value. Good management means knowing which decisions to make yourself and which to hand off. The same applies to orchestrating agents."}),e.jsx(s,{title:"The Delegation Depth Trap",children:"Over-delegation often compounds across layers. An orchestrator over-delegates to a sub-agent, which in turn over-delegates to its own sub-agents. Each layer adds latency and reduces visibility. By the time results surface back up the chain, the overhead has dwarfed the task. Cap delegation depth intentionally and review any chain deeper than two or three levels."}),e.jsx(n,{title:"Recognising and Preventing Over-Delegation",exercises:[{id:"od-1",difficulty:"beginner",question:"For each of the following tasks, decide if delegation is justified or if it is over-delegation: (a) convert a list of strings to uppercase; (b) translate a 5,000-word document into three languages; (c) check if a number is even.",hint:"Consider whether parallelism, specialisation, or context economy applies.",solution:"(a) Over-delegation: trivial in-line operation, no parallelism benefit, no specialisation needed. (b) Justified: three independent translations benefit from parallel specialist sub-agents; the task is substantial and self-contained. (c) Over-delegation: single-step deterministic operation, spawning a sub-agent for this is absurd overhead."},{id:"od-2",difficulty:"intermediate",question:"An orchestrator delegates a task to Sub-agent A. Sub-agent A's entire job is to call Sub-agent B and pass the result back. Sub-agent B does the same to Sub-agent C, which actually does the work. Describe the problems with this design.",hint:"Think about latency, failure propagation, and what value A and B actually add.",solution:"Problems: (1) Pure overhead — A and B contribute no value; each adds a round-trip of latency and an additional point of failure. (2) Failure propagation is harder to debug — if C fails, the error must propagate back through B and A before the orchestrator sees it, obscuring the original failure point. (3) Context dilution — each handoff may paraphrase or lose precision from the original brief. The orchestrator should delegate directly to C."},{id:"od-3",difficulty:"advanced",question:"Design a heuristic the orchestrating agent could apply before delegating any sub-task to catch likely over-delegation. The heuristic should involve estimated task duration, independence score, and minimum delegation overhead. Give a worked example.",hint:"Express the condition as: delegate if [estimated work time] > [overhead] AND [independence is high].",solution:"Heuristic: Delegate if (estimated_task_time > 3 * delegation_overhead) AND (independence_score >= 2). Reasoning: the task must take meaningfully longer than the coordination cost to justify it; and it must be genuinely independent. Example: estimating a ten-step research task at 60 seconds, with 5 seconds of delegation overhead — ratio is 12x, well above 3x threshold. Independence is high (self-contained, no parent state needed). Delegate. Counterexample: converting a string to uppercase — estimated 0.1 seconds, overhead 5 seconds, ratio 0.02x. Don't delegate."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Duplicate Work"}),e.jsx("p",{children:"In multi-agent systems, work can be duplicated in ways that never occur in single-agent systems. Two sub-agents, independently briefed, may perform the same retrieval, the same computation, or the same analysis — unaware of each other's efforts. The output is not wrong, but it represents wasted resources, inconsistent results, and potential conflicts when the duplicate outputs disagree."}),e.jsx(t,{title:"Duplicate Work in Multi-Agent Systems",number:"Concept 7.10",children:"Duplicate work occurs when two or more sub-agents independently perform the same task because the orchestrator failed to coordinate their scope. Unlike redundancy (which is intentional and serves fault-tolerance), duplicate work is unintentional. It wastes compute, introduces inconsistency (two sub-agents querying the same live source may receive different results if the source changes between calls), and makes the final integration harder when contradictory duplicates must be reconciled."}),e.jsx("p",{children:"The root cause is almost always insufficient scope definition in the brief. When multiple sub-agents are given overlapping domains without explicit boundaries, they will naturally overlap in their work. The fix is to partition scope at brief-writing time: each sub-agent should have a clearly defined territory that does not intersect with any other sub-agent's territory."}),e.jsx(i,{type:"intuition",title:"The Scope Partition Test",children:"Before launching multiple sub-agents in parallel, draw the scope boundaries for each one and check: do any two agents have tasks that could require the same external call, the same data retrieval, or the same computation? If yes, either partition the scope more clearly or centralise the shared step in the orchestrator before spawning the sub-agents."}),e.jsx(s,{title:"Inconsistency from Duplicate Queries",children:"When two sub-agents independently query a live data source (an API, a database, a web page), they may receive different responses if the source changes between their calls. Both results are accurate at their respective moments, but they are inconsistent with each other. An orchestrator combining them produces an incoherent output. For time-sensitive data, either run the query once centrally and pass the result to both sub-agents, or accept and document the inconsistency."}),e.jsx(n,{title:"Eliminating Duplicate Work",exercises:[{id:"dw-1",difficulty:"beginner",question:'An orchestrator launches a "competitive analysis" sub-agent and a "market positioning" sub-agent simultaneously. Both are likely to independently research the same three main competitors. How could the orchestrator prevent this duplication?',hint:"Think about whether the shared research step should happen before the sub-agents are launched.",solution:"The orchestrator should perform (or delegate to a single sub-agent) the competitor research first, then pass the findings as context in the briefs for both the competitive analysis and market positioning sub-agents. This way, both sub-agents work from the same research, avoid duplicate retrieval, and produce consistent results."},{id:"dw-2",difficulty:"intermediate",question:"Design explicit scope partition rules for three sub-agents tasked with analysing a company: one covering financial performance, one covering product strategy, and one covering organisational health. Make sure the rules prevent any topic from being covered by more than one agent.",hint:"Be specific about what belongs to each agent and what falls in the gaps between them.",solution:"Financial performance: covers revenue, profitability, cash flow, debt, and investor metrics. Explicitly excludes product roadmap and headcount costs (those go to strategy and org). Product strategy: covers product portfolio, roadmap, competitive positioning, and customer feedback on products. Excludes P&L impact of products (financial) and team structure behind products (org). Organisational health: covers headcount, retention, leadership, culture indicators, and hiring trends. Excludes individual product decisions (strategy) and company-level financials (financial). Rule: when a topic could belong to two agents, assign it to the agent whose core purpose it most directly serves."},{id:"dw-3",difficulty:"advanced",question:"Intentional redundancy (running the same task twice for fault tolerance) and unintentional duplicate work look similar from outside the system. How would you design the orchestrator so the two are always distinguishable in logs and outputs?",hint:"Think about metadata, naming conventions, and how results are merged differently in each case.",solution:'Design: (1) Tag every sub-agent invocation with a purpose field: "redundant" vs "unique". Redundant agents are given the same task ID; unique agents get distinct task IDs. (2) Merge logic differs: redundant results go through a comparison step (are they consistent?) before the best one is selected; unique results are collected and combined without comparison. (3) In logs, redundant invocations are grouped under one logical task; duplicate work appears as two separate logical tasks covering the same domain — detectable by comparing scope tags. (4) A post-hoc audit checks for any two "unique" tasks with overlapping domain tags — these indicate unintentional duplication.'}]})]})}const O=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function b(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Context Overload"}),e.jsx("p",{children:"One of the benefits of delegation is that sub-agents get clean, focused contexts. But that benefit disappears when orchestrators pass too much context into each brief. Context overload is the anti-pattern of providing a sub-agent with far more background than it needs — often the orchestrator's entire conversation history — in an attempt to be thorough. The result is a sub-agent that struggles to identify what is relevant and often performs worse than it would with less information."}),e.jsx(t,{title:"Context Overload",number:"Concept 7.11",children:"Context overload occurs when a sub-agent's input contains so much information that the signal relevant to its task is diluted by noise. Language models attend to everything in their context window, which means irrelevant content competes for attention with the content that matters. A sub-agent given the full history of a complex project when it only needs three specific facts will often produce outputs that reflect the distracting content rather than the relevant signal."}),e.jsx("p",{children:"The natural impulse is to provide more context because it feels safer — the sub-agent can pick what it needs. But this assumption is flawed. Sub-agents are not efficient skimmers. They reason over their full context, and long contexts with buried relevant information produce less reliable outputs than short contexts with the right information front and centre."}),e.jsx(a,{title:"Extract, Don't Dump",number:"Principle 7.6",children:"When preparing a sub-agent brief, extract only the facts the sub-agent needs and discard everything else. This requires the orchestrator to do the filtering work itself — which is harder than passing everything through. But the effort pays off in sub-agent output quality. A two-paragraph brief with the right three facts will outperform a twenty-page dump every time."}),e.jsx(s,{title:"The 'Just In Case' Dump",children:'A frequent form of context overload is passing the entire prior conversation "just in case" the sub-agent needs something in it. This is almost never the right choice. Prior conversation contains tentative reasoning, rejected options, intermediate thoughts, and other artifacts that confuse rather than help. The orchestrator should resolve its own reasoning first and pass only the settled conclusions.'}),e.jsx(n,{title:"Diagnosing and Fixing Context Overload",exercises:[{id:"co-1",difficulty:"beginner",question:"An orchestrator passes its entire 10,000-token conversation history to a sub-agent whose only task is to format a list of five names into alphabetical order. What is wrong here, and what should the brief contain instead?",hint:"Think about what the sub-agent actually needs to perform this task.",solution:'The sub-agent needs only the five names and the instruction to return them alphabetically. Nothing else in the 10,000-token history is relevant. The inflated context wastes tokens, slows inference, and risks the sub-agent latching onto irrelevant content. The brief should be: "Return the following names in alphabetical order: [list of five names]. Output format: a JSON array of strings."'},{id:"co-2",difficulty:"intermediate",question:"An orchestrator has spent twenty reasoning steps exploring three different approaches to a problem before settling on Approach C. It now delegates implementation to a sub-agent. Which parts of those twenty steps should appear in the sub-agent brief, and which should be omitted?",hint:"Distinguish between the decision (relevant) and the deliberation (usually not).",solution:"Include: the final decision (Approach C was chosen), the key constraints that led to it (e.g., Approach A was rejected due to latency, Approach B due to cost), and any implementation-relevant specifications derived from those steps. Omit: the full deliberation process, the details of Approaches A and B unless they contain constraints that still apply, and any tentative conclusions that were later revised. The sub-agent needs to know what to build and why, not the full history of how the decision was reached."},{id:"co-3",difficulty:"advanced",question:"Design a context extraction protocol for an orchestrator preparing to delegate. Define the steps it should follow to distil its current state into a minimal, high-quality brief. Include how it decides what is relevant.",hint:"Think of it as a compression algorithm with a relevance filter.",solution:`Protocol: (1) Write the task goal first. (2) For each piece of information in the orchestrator's current state, ask: "If the sub-agent didn't have this, would it make a worse decision or take a wrong action?" If yes, include it. If no, exclude it. (3) Convert any relevant information from conversational form to declarative facts (e.g., "we considered X but rejected it because Y" becomes "X is not an option because Y"). (4) Check the resulting brief length: if it exceeds ~500 tokens for a routine task, review for additional cuts. (5) Verify completeness by reading the brief cold — could a fresh agent do the task correctly from this alone?`}]})]})}const B=Object.freeze(Object.defineProperty({__proto__:null,default:b},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Orphan Agents"}),e.jsx("p",{children:"An orphan agent is a sub-agent that has been started but whose results will never be collected, whose errors will never be handled, and which may continue consuming resources long after the parent task has concluded. Orphan agents are one of the costliest failure modes in multi-agent systems — invisible, persistent, and capable of causing cascading problems in the environment they operate in."}),e.jsx(t,{title:"Orphan Agents",number:"Concept 7.12",children:"An orphan agent is a sub-agent that has lost its connection to the orchestrator that spawned it. This happens when an orchestrator fails or exits without cancelling its sub-agents, when a sub-agent is launched with no timeout or cancellation mechanism, or when the orchestrator simply moves on and forgets to collect results. Orphan agents may continue executing, consuming API quotas, writing to external systems, or holding locks — all without any parent to account for their behaviour."}),e.jsx("p",{children:"Preventing orphan agents requires the same discipline as preventing resource leaks in software: every resource opened must be explicitly closed. Every sub-agent launched must have a corresponding lifecycle: a timeout or completion condition, a cancellation path for when the parent exits early, and a mechanism for the orchestrator to verify that all sub-agents have reached a terminal state before the task is considered complete."}),e.jsx(i,{type:"tip",title:"The Ledger Pattern",children:"Maintain a ledger of every sub-agent launched, indexed by ID, with columns for launch time, expected completion time, current status, and result. Before the orchestrator concludes, it checks the ledger: any sub-agent not in a terminal state (completed, failed, cancelled) must be explicitly cancelled. This simple pattern prevents the most common forms of orphaning."}),e.jsx(s,{title:"Orphan Agents in External Systems",children:"An orphan agent that holds an external resource — an open database transaction, a checked-out lock, an authenticated session — can block other agents or users from accessing that resource indefinitely. External systems may not have the ability to detect or time out hung agent connections. Design every sub-agent to release external resources explicitly before it terminates, and set resource-level timeouts independent of agent lifecycle."}),e.jsx(n,{title:"Preventing and Detecting Orphan Agents",exercises:[{id:"oa-1",difficulty:"beginner",question:"Name three conditions that can cause an orchestrator to orphan a sub-agent it launched. For each, describe what the sub-agent continues to do after it is orphaned.",hint:"Think about orchestrator failure, task completion without cleanup, and timeout omission.",solution:"(1) Orchestrator crashes mid-task: the sub-agent continues executing with no one to collect its result or cancel it. (2) Orchestrator marks the task complete before waiting for all sub-agents: the remaining sub-agents continue running and may write results to locations no one will read. (3) No timeout set and the sub-agent enters an infinite loop or waits on an unresponsive external service: it runs indefinitely consuming resources."},{id:"oa-2",difficulty:"intermediate",question:"An orchestrator is cancelled by the user midway through a multi-agent task. Design the shutdown sequence the orchestrator should follow to avoid leaving orphan agents behind.",hint:"Think about order of operations: what must happen before the orchestrator terminates?",solution:"Shutdown sequence: (1) Receive cancellation signal. (2) Stop launching any new sub-agents. (3) Send cancellation signals to all sub-agents currently running (identified from the ledger). (4) Wait up to a brief grace period for sub-agents to acknowledge cancellation and release external resources. (5) For any sub-agent that does not acknowledge within the grace period, force-terminate it at the infrastructure level. (6) Log the final state of all sub-agents (cancelled, completed, force-terminated). (7) Release any resources the orchestrator itself holds. Then exit."},{id:"oa-3",difficulty:"advanced",question:"In a long-running production system, orphan agents from previous runs are discovered still executing after the orchestrators that spawned them have long since exited. Design a recovery mechanism that can detect and clean up these orphans without human intervention.",hint:"Think about heartbeats, expiry timestamps, and a background watchdog process.",solution:"Recovery mechanism: (1) Each sub-agent registers itself with a central registry on start, recording its ID, parent orchestrator ID, start time, and a lease expiry time. (2) Each sub-agent renews its lease periodically (heartbeat). (3) A watchdog process scans the registry for entries past their lease expiry that have not been renewed — these are candidate orphans. (4) The watchdog checks whether the parent orchestrator is still active. If not, it marks the sub-agent as orphaned and sends a termination signal. (5) The watchdog logs all cleanups with reasons, enabling post-mortem analysis of why orphaning occurred. (6) Recovered orphan results are preserved in a dead-letter store for potential inspection."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));export{x as a,j as b,T as c,A as d,q as e,S as f,D as g,C as h,I as i,O as j,B as k,P as l,k as s};
